import { createContext, useContext, useState, ReactNode } from 'react';
import { IntlProvider } from 'react-intl';
import enMessages from './locales/en.json';
import trMessages from './locales/tr.json';

const messages: Record<string, any> = {
    en: enMessages,
    tr: trMessages,
};

interface LocaleContextType {
    locale: string;
    setLocale: (locale: string) => void;
}

const LocaleContext = createContext<LocaleContextType | undefined>(undefined);

export const useLocale = () => {
    const context = useContext(LocaleContext);
    if (!context) {
        throw new Error('useLocale must be used within a LocaleProvider');
    }
    return context;
};

export const LocaleProvider = ({ children }: { children: ReactNode }) => {
    // Use browser language as default, fallback to en
    const browserLocale = navigator.language.split(/[-_]/)[0];
    const [locale, setLocale] = useState<string>(['en', 'tr'].includes(browserLocale) ? browserLocale : 'en');

    return (
        <LocaleContext.Provider value={{ locale, setLocale }}>
            <IntlProvider locale={locale} messages={messages[locale]}>
                {children}
            </IntlProvider>
        </LocaleContext.Provider>
    );
};

import { useEffect, useState } from 'react';
import { Title, Button, TextInput, Loader, Center, Group, ActionIcon, useMantineColorScheme, useComputedColorScheme, Image, Tooltip, Badge } from '@mantine/core';
import { useForm } from '@mantine/form';
import { modals } from '@mantine/modals';
import { notifications } from '@mantine/notifications';
import { IconPlus, IconSun, IconMoon } from '@tabler/icons-react';
import { DragDropContext, Droppable, Draggable, DropResult } from '@hello-pangea/dnd';
import { useIntl } from 'react-intl';

import { TodoApi } from '../api/api';
import { TodoItem, TodoStatus } from '../models/todo';
import { TodoItemCard } from '../components/TodoItemCard';
import { useLocale } from '../LocaleContext';
import './TodoPage.css';

export default function TodoPage() {
    const [todos, setTodos] = useState<TodoItem[]>([]);
    const [loading, setLoading] = useState(true);

    const intl = useIntl();
    const { locale, setLocale } = useLocale();
    const { setColorScheme } = useMantineColorScheme();
    const computedColorScheme = useComputedColorScheme('dark', { getInitialValueInEffect: true });

    const form = useForm({
        initialValues: { title: '' },
        validate: {
            title: (value: string) => (value.trim().length === 0 ? 'Title is required' : null),
        },
    });

    const loadTodos = async () => {
        try {
            setLoading(true);
            const data = await TodoApi.getTodos();
            setTodos(data.sort((a, b) => b.id - a.id));
        } catch (error) {
            notifications.show({ title: intl.formatMessage({ id: 'notification.error' }), message: intl.formatMessage({ id: 'notification.errorFetch' }), color: 'red' });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { loadTodos(); }, []);

    const handleAddTodo = async (values: typeof form.values) => {
        try {
            const newTodo = await TodoApi.createTodo({
                title: values.title.trim(),
                status: TodoStatus.Todo,
            });
            setTodos((prev) => [newTodo, ...prev]);
            form.reset();
            notifications.show({ title: intl.formatMessage({ id: 'notification.success' }), message: intl.formatMessage({ id: 'notification.successAdd' }), color: 'teal' });
        } catch (error) {
            notifications.show({ title: intl.formatMessage({ id: 'notification.error' }), message: intl.formatMessage({ id: 'notification.errorAdd' }), color: 'red' });
        }
    };

    // Kept this for simple toggle capability, mostly replaced by Drag & Drop
    const handleToggleTodo = async (id: number, currentStatus: TodoStatus) => {
        const todoToUpdate = todos.find((t) => t.id === id);
        if (!todoToUpdate) return;

        let newStatus = currentStatus === TodoStatus.Done ? TodoStatus.Todo : TodoStatus.Done;

        try {
            const updatedItem = { ...todoToUpdate, status: newStatus };
            await TodoApi.updateTodo(id, updatedItem);
            setTodos((prev) => prev.map((t) => (t.id === id ? updatedItem : t)));
        } catch (error) {
            notifications.show({ title: intl.formatMessage({ id: 'notification.error' }), message: intl.formatMessage({ id: 'notification.errorUpdate' }), color: 'red' });
        }
    };

    const handleEditTodo = async (id: number, newTitle: string) => {
        const todoToUpdate = todos.find((t) => t.id === id);
        if (!todoToUpdate || todoToUpdate.title === newTitle) return;

        try {
            const updatedItem = { ...todoToUpdate, title: newTitle };
            await TodoApi.updateTodo(id, updatedItem);
            setTodos((prev) => prev.map((t) => (t.id === id ? updatedItem : t)));
            notifications.show({ title: intl.formatMessage({ id: 'notification.success' }), message: intl.formatMessage({ id: 'notification.successEdit' }), color: 'teal' });
        } catch (error) {
            notifications.show({ title: intl.formatMessage({ id: 'notification.error' }), message: intl.formatMessage({ id: 'notification.errorEdit' }), color: 'red' });
        }
    };

    const deleteWithApi = async (id: number) => {
        try {
            await TodoApi.deleteTodo(id);
            setTodos((prev) => prev.filter((t) => t.id !== id));
            notifications.show({ title: intl.formatMessage({ id: 'notification.deleted' }), message: intl.formatMessage({ id: 'notification.successDelete' }), color: 'blue' });
        } catch (error) {
            notifications.show({ title: intl.formatMessage({ id: 'notification.error' }), message: intl.formatMessage({ id: 'notification.errorDelete' }), color: 'red' });
        }
    };

    const handleDeleteClick = (id: number) => {
        modals.openConfirmModal({
            title: intl.formatMessage({ id: 'modal.deleteTitle' }),
            centered: true,
            children: <p>{intl.formatMessage({ id: 'modal.deleteMessage' })}</p>,
            labels: { confirm: intl.formatMessage({ id: 'modal.deleteConfirm' }), cancel: intl.formatMessage({ id: 'modal.deleteCancel' }) },
            confirmProps: { color: 'red' },
            onConfirm: () => deleteWithApi(id),
        });
    };

    const onDragEnd = async (result: DropResult) => {
        const { source, destination, draggableId } = result;

        if (!destination) return;
        if (source.droppableId === destination.droppableId && source.index === destination.index) return;

        const newStatus = parseInt(destination.droppableId) as TodoStatus;
        const todoId = parseInt(draggableId);

        // Optimistic UI update
        const todoIndex = todos.findIndex(t => t.id === todoId);
        if (todoIndex === -1) return;

        const originalTodo = todos[todoIndex];
        if (originalTodo.status === newStatus && source.index === destination.index) return;

        const updatedTodos = [...todos];
        updatedTodos[todoIndex] = { ...originalTodo, status: newStatus };
        setTodos(updatedTodos);

        // Send to API
        try {
            await TodoApi.updateTodo(todoId, { ...originalTodo, status: newStatus });
        } catch (error) {
            // Revert on failure
            setTodos(todos);
            notifications.show({ title: intl.formatMessage({ id: 'notification.error' }), message: intl.formatMessage({ id: 'notification.errorUpdate' }), color: 'red' });
        }
    };

    const columns = [
        { id: TodoStatus.Todo.toString(), title: intl.formatMessage({ id: 'column.todo' }), color: 'grape', status: TodoStatus.Todo },
        { id: TodoStatus.InProgress.toString(), title: intl.formatMessage({ id: 'column.inProgress' }), color: 'yellow', status: TodoStatus.InProgress },
        { id: TodoStatus.Done.toString(), title: intl.formatMessage({ id: 'column.done' }), color: 'green', status: TodoStatus.Done }
    ];

    return (
        <div className="page-wrapper">
            <Group justify="space-between" align="center" mb="xl">
                <Title order={1} className="header-title">{intl.formatMessage({ id: 'app.title' })}</Title>
                <Group gap="sm">
                    <Tooltip label="English">
                        <ActionIcon variant={locale === 'en' ? 'light' : 'subtle'} onClick={() => setLocale('en')} size="lg" radius="xl">
                            <Image src="https://flagcdn.com/w40/gb.png" w={24} h={24} style={{ borderRadius: '50%', objectFit: 'cover' }} />
                        </ActionIcon>
                    </Tooltip>
                    <Tooltip label="T├╝rk├ºe">
                        <ActionIcon variant={locale === 'tr' ? 'light' : 'subtle'} onClick={() => setLocale('tr')} size="lg" radius="xl">
                            <Image src="https://flagcdn.com/w40/tr.png" w={24} h={24} style={{ borderRadius: '50%', objectFit: 'cover' }} />
                        </ActionIcon>
                    </Tooltip>
                    <ActionIcon onClick={() => setColorScheme(computedColorScheme === 'light' ? 'dark' : 'light')} variant="default" size="lg" aria-label="Toggle color scheme" ml="sm">
                        {computedColorScheme === 'dark' ? <IconSun stroke={1.5} /> : <IconMoon stroke={1.5} />}
                    </ActionIcon>
                </Group>
            </Group>

            <form onSubmit={form.onSubmit(handleAddTodo)} className="add-container">
                <TextInput placeholder={intl.formatMessage({ id: 'app.addPlaceholder' })} style={{ flex: 1 }} size="md" radius="md" {...form.getInputProps('title')} />
                <Button type="submit" size="md" radius="md" variant="gradient" gradient={{ from: 'indigo', to: 'cyan' }} leftSection={<IconPlus size={18} />}>
                    {intl.formatMessage({ id: 'app.addButton' })}
                </Button>
            </form>

            {loading ? (
                <Center pt="xl"><Loader color="indigo" type="bars" /></Center>
            ) : (
                <DragDropContext onDragEnd={onDragEnd}>
                    <div className="kanban-board">
                        {columns.map(col => (
                            <div key={col.id} className={`kanban-column status-${col.status}`}>
                                <Group justify="space-between" className="kanban-column-header">
                                    <Title order={3} size="h4">{col.title}</Title>
                                    <Badge color={col.color} variant="light" size="lg" circle>
                                        {todos.filter(t => t.status === col.status).length}
                                    </Badge>
                                </Group>

                                <Droppable droppableId={col.id}>
                                    {(provided) => (
                                        <div ref={provided.innerRef} {...provided.droppableProps} className="kanban-list">
                                            {todos
                                                .filter(t => t.status === col.status)
                                                .map((todo, index) => (
                                                    <Draggable key={todo.id.toString()} draggableId={todo.id.toString()} index={index}>
                                                        {(provided, snapshot) => (
                                                            <div
                                                                ref={provided.innerRef}
                                                                {...provided.draggableProps}
                                                                {...provided.dragHandleProps}
                                                                className="draggable-card-wrapper"
                                                                style={{
                                                                    ...provided.draggableProps.style,
                                                                    opacity: snapshot.isDragging ? 0.8 : 1,
                                                                    transform: snapshot.isDragging ? provided.draggableProps.style?.transform : 'translate(0, 0)'
                                                                }}
                                                            >
                                                                <TodoItemCard
                                                                    todo={todo}
                                                                    onToggle={(id) => handleToggleTodo(id, todo.status)}
                                                                    onDeleteClick={handleDeleteClick}
                                                                    onEdit={handleEditTodo}
                                                                />
                                                            </div>
                                                        )}
                                                    </Draggable>
                                                ))}
                                            {provided.placeholder}
                                        </div>
                                    )}
                                </Droppable>
                            </div>
                        ))}
                    </div>
                </DragDropContext>
            )}
        </div>
    );
}
